import { z } from 'zod';

type DefaultSchema = {
    [key: string]: {
        output?: any;
    };
};
type FetchSchema = {
    [key: string]: {
        input?: z.ZodSchema;
        output?: z.ZodSchema;
        query?: z.ZodSchema;
    };
};
type Strict<T extends FetchSchema> = {
    schema: T;
};

export type { DefaultSchema, FetchSchema, Strict };
